{
  "grammar": [
    {
      "pattern": "A 比 B + adjective",
      "structure": ["A", "比", "B", "adjective"],
      "explanation_en": "Use '比' to compare two items, stating that A is more [adjective] than B.",
      "title": "Basic Comparison with 比",
      "meaning": "A is more [adjective] than B",
      "when_to_use": ["Comparing prices, sizes, distances, or qualities of two items", "Stating a clear difference between two options"],
      "when_not_to_use": ["When the difference is small or uncertain", "When comparing more than two items at once"],
      "pragmatic_notes": "In Taiwan, '比' is very common in daily conversation, especially when discussing food or shopping choices. It's neutral and polite.",
      "word_order_notes": "The structure is fixed: A + 比 + B + adjective. Do not add '很' or other degree adverbs before the adjective.",
      "english_contrast": "In English, we say 'A is more [adjective] than B'. In Chinese, the word order is A + 比 + B + adjective, without 'more'.",
      "korean_contrast": "In Korean, you use 'A가 B보다 더 [adjective]' (A-ga B-boda deo [adjective]). The Chinese structure is similar but without '더' (deo).",
      "negative_examples": [
        {
          "text": "這個餐廳比那個餐廳很貴。",
          "error": "Do not use '很' after '比' + B. The adjective should stand alone."
        }
      ],
      "incorrect_examples": [
        {
          "text": "這個餐廳比那個餐廳很貴。",
          "error": "Do not use '很' after '比' + B. The adjective should stand alone."
        }
      ],
      "transformation_drills": ["Change '這個餐廳很貴' to '這個餐廳比那個餐廳貴'"],
      "production_drills": ["Compare the price of two drinks using '比'"],
      "common_error_patterns": ["Adding '很' or '非常' after '比' + B"],
      "repair_feedback": {
        "word_order": "Remember: A + 比 + B + adjective, no extra words.",
        "politeness": "This structure is neutral and polite.",
        "vocabulary": "Use adjectives like 貴, 便宜, 近, 遠, 大, 小."
      }
    },
    {
      "pattern": "A 跟 B 差不多",
      "structure": ["A", "跟", "B", "差不多"],
      "explanation_en": "Use '跟...差不多' to say that two items are similar or almost the same in a certain aspect.",
      "title": "Similarity with 差不多",
      "meaning": "A and B are about the same",
      "when_to_use": ["When two items have similar prices, sizes, or qualities", "When you want to say there's no big difference"],
      "when_not_to_use": ["When there is a clear difference", "When you want to emphasize one is better"],
      "pragmatic_notes": "In Taiwan, '差不多' is very common in casual conversation, especially when comparing food or prices. It's a soft way to say 'no big difference'.",
      "word_order_notes": "The structure is: A + 跟 + B + 差不多. You can add a noun after '差不多' if needed, e.g., 'A 跟 B 差不多貴'.",
      "english_contrast": "In English, we say 'A and B are about the same'. In Chinese, the structure is A + 跟 + B + 差不多.",
      "korean_contrast": "In Korean, you use 'A와 B가 비슷하다' (A-wa B-ga biseuthada). The Chinese structure is similar but uses '差不多' instead of '비슷하다'.",
      "negative_examples": [
        {
          "text": "這個餐廳跟那個餐廳差不多很貴。",
          "error": "Do not add '很' after '差不多'. The adjective should come after '差不多' without '很'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "這個餐廳跟那個餐廳差不多很貴。",
          "error": "Do not add '很' after '差不多'. The adjective should come after '差不多' without '很'."
        }
      ],
      "transformation_drills": ["Change '這個餐廳很貴，那個餐廳也很貴' to '這個餐廳跟那個餐廳差不多貴'"],
      "production_drills": ["Compare the size of two drinks using '差不多'"],
      "common_error_patterns": ["Adding '很' after '差不多'"],
      "repair_feedback": {
        "word_order": "Remember: A + 跟 + B + 差不多 + (adjective), no '很'.",
        "politeness": "This structure is casual and friendly.",
        "vocabulary": "Use adjectives like 貴, 便宜, 大, 小, 近, 遠."
      }
    },
    {
      "pattern": "A 沒有 B + adjective",
      "structure": ["A", "沒有", "B", "adjective"],
      "explanation_en": "Use '沒有' to express that A is not as [adjective] as B.",
      "title": "Negative Comparison with 沒有",
      "meaning": "A is not as [adjective] as B",
      "when_to_use": ["When you want to say A is less [adjective] than B", "When comparing qualities like price, size, or distance"],
      "when_not_to_use": ["When A is more [adjective] than B (use 比 instead)", "When the comparison is about equality (use 差不多 instead)"],
      "pragmatic_notes": "In Taiwan, '沒有' is commonly used in negative comparisons, especially when discussing prices or convenience. It's polite and clear.",
      "word_order_notes": "The structure is: A + 沒有 + B + adjective. Do not add '很' before the adjective.",
      "english_contrast": "In English, we say 'A is not as [adjective] as B'. In Chinese, the structure is A + 沒有 + B + adjective.",
      "korean_contrast": "In Korean, you use 'A가 B만큼 [adjective]하지 않다' (A-ga B-mankeum [adjective]haji anta). The Chinese structure is simpler with '沒有'.",
      "negative_examples": [
        {
          "text": "這個餐廳沒有那個餐廳很貴。",
          "error": "Do not use '很' after '沒有' + B. The adjective should stand alone."
        }
      ],
      "incorrect_examples": [
        {
          "text": "這個餐廳沒有那個餐廳很貴。",
          "error": "Do not use '很' after '沒有' + B. The adjective should stand alone."
        }
      ],
      "transformation_drills": ["Change '這個餐廳比那個餐廳便宜' to '那個餐廳沒有這個餐廳便宜'"],
      "production_drills": ["Compare the convenience of two stores using '沒有'"],
      "common_error_patterns": ["Adding '很' after '沒有' + B"],
      "repair_feedback": {
        "word_order": "Remember: A + 沒有 + B + adjective, no '很'.",
        "politeness": "This structure is neutral and polite.",
        "vocabulary": "Use adjectives like 貴, 便宜, 近, 遠, 方便, 麻煩."
      }
    }
  ]
}
